code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100vh;
  background: #d4ff3f;
  overflow: hidden;
}

.nav {
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 2em 1em 2em 2em;
  font-family: "Monument Extended";
}

.nav > * {
  position: relative;
}

.nav a {
  position: relative;
  text-decoration: none;
  text-transform: uppercase;
  color: #000;
  padding: 0 1em;
  font-size: 12px;
  font-weight: 300;
}

@media (max-width: 900px) {
  .nav .nav-links {
    display: none;
  }

  .nav {
    justify-content: center;
  }
}

.header {
  width: 100%;
  height: 30vh;
  padding: 2em;
  display: flex;
  align-items: center;
}

.header .col {
  width: 60%;
}

.header .col:nth-child(2) {
  width: 40%;
}

.header h1 {
  position: relative;
  font-family: "Monument Extended";
  font-size: 100px;
  text-transform: uppercase;
  line-height: 1;
  margin: 0;
}

.play-wrapper {
  position: relative;
  width: 100%;
  height: 80px;
  background: url("https://images.unsplash.com/photo-1515375380578-a0587184cedd?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=2899&q=80")
    no-repeat 50% 50%;
  background-size: cover;
  border-radius: 50px;
  display: flex;
  justify-content: flex-start;
  align-items: center;
  padding: 0.4em;
}

.play-btn {
  width: 70px;
  height: 70px;
  background: #000;
  border-radius: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
}

.play-btn ion-icon {
  color: #d4ff3f;
}

.pattern {
  text-align: center;
  padding: 1em 0;
  letter-spacing: 10px;
  opacity: 0.2;
}

.copy p {
  font-family: "Monument Extended";
  font-size: 10px;
  font-weight: 300;
  line-height: 1.5;
}

.btn-container {
  width: 100%;
  padding: 2em;
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: -2em;
}

.btns {
  display: flex;
}

.btn {
  border: 1px solid #000;
  margin-right: 1em;
  padding: 0.4em 0.8em;
  border-radius: 20px;
  font-family: "Monument Extended";
  font-size: 10px;
  font-weight: 300;
}

.divider {
  width: 70%;
}

.hr {
  width: 100%;
  height: 1px;
  background: rgba(0, 0, 0, 0.2);
}

.hero {
  position: relative;
  width: 95%;
  height: 50vh;
  border-radius: 40px 40px 0 0;
  margin: 2em auto;
  /* background: url("https://images.unsplash.com/photo-1655669661634-2a2692fad546?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=2832&q=80") */
  /* no-repeat 50% 50%; */
  background-size: cover;
  display: flex;
  justify-content: flex-end;
  align-items: flex-start;
}

.hero img {
  width: 100%;
}

.hero-wrapper {
  position: absolute;
  width: 0;
  height: 100%;
  background: #d4ff3f;
}

.arrow {
  position: absolute;
  width: 120px;
  height: 120px;
  border: 4px solid rgb(45, 45, 45);
  border-radius: 100%;
  background: #000;
  top: -1.4em;
  right: 4em;
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 40px;
  color: #d4ff3f;
  font-family: "Dahlia";
  transform: rotate(-45deg);
}

.marquee {
  position: absolute;
  bottom: 0%;
  width: 100%;
  margin: 0 auto;
  padding: 1em 0;
  white-space: nowrap;
  overflow: hidden;
  z-index: 3;
  background: #000;
  display: flex;
  align-items: center;
}
.marquee span {
  font-family: "Monument Extended";
  text-transform: uppercase;
  font-weight: 400;
  color: #d4ff3f;
  mix-blend-mode: normal !important;
  font-size: 4em;
  text-transform: uppercase;
  padding-left: -10%;
  animation: marquee-animation 80s linear infinite;
}

@keyframes marquee-animation {
  0% {
    transform: translate(0, 0);
  }
  100% {
    transform: translate(-100%, 0);
  }
}
